def analyze_best_pose_hotspots():
    try:
        # Load the data, assuming the user's header format (GLQ is manually fixed to GLN if needed)
        df = pd.read_csv(io.StringIO(data_snippet))
    except Exception as e:
        print(f"Error loading data: {e}. Ensure the file is correct or check the manual loading in the script.")
        return

    # --- 1. Calculate ΔΔG_NAD and Identify the Best Pose per Molecule ---
    
    # Baseline NAD binding energy (ΔG_NAD, apo) from 4zzj_nad_p53
    ref_nad_row = df[df['Molecule_Name'] == '4zzj_nad_p53']
    delta_g_nad_apo = ref_nad_row['NAD_ΔTOTAL'].iloc[0]
    
    # Calculate ΔΔG_NAD for all rows
    df['ΔΔG_NAD'] = df['NAD_ΔTOTAL'] - delta_g_nad_apo
    
    # Find the single BEST pose (most negative ΔΔG_NAD) for each molecule
    idx_best_pose = df.groupby('Molecule_Name')['ΔΔG_NAD'].idxmin()
    best_pose_df = df.loc[idx_best_pose].copy()

    # Filter out the NAD-only reference (since it has no allosteric ligand/pose)
    best_pose_df = best_pose_df[best_pose_df['Molecule_Name'] != '4zzj_nad_p53']
    
    # --- 2. Aggregate Allosteric Residue Contributions from ONLY Best Poses ---
    
    allost_tags = [col for col in best_pose_df.columns if col.startswith('ALLOST_RES_T_')]
    
    all_allost_residues = []
    
    for _, row in best_pose_df.iterrows():
        # Iterate through the top 10 allosteric residue columns
        for i in range(1, 11):
            tag_col = f'ALLOST_RES_T_{i:02d}'
            energy_col = f'ALLOST_RES_E_{i:02d}'
            
            residue_tag = row[tag_col]
            residue_energy = row[energy_col]
            
            # Check for NaN/missing values
            if pd.notna(residue_tag) and pd.notna(residue_energy):
                # Include the pose's activation efficacy (ΔΔG_NAD) and affinity (ΔTOTAL)
                all_allost_residues.append({
                    'Residue': residue_tag,
                    'Energy': residue_energy,
                    'ΔΔG_NAD': row['ΔΔG_NAD'],
                    'ΔG_Allost': row['ΔTOTAL']
                })

    allost_res_df = pd.DataFrame(all_allost_residues)
    
    # --- 3. Final Analysis: Correlating Residue Energy with Activation Efficacy ---
    
    # Get the list of unique, highly frequent allosteric residues
    frequent_residues = allost_res_df['Residue'].value_counts().head(10).index.tolist()
    
    # Calculate the average energy contribution and the average activation efficacy for each pose-residue pair
    analysis_results = []
    
    for residue in frequent_residues:
        # Filter the DataFrame for all instances of this specific residue
        subset = allost_res_df[allost_res_df['Residue'] == residue]
        
        # Calculate Correlation: Does making this residue interaction more favorable (more negative Energy)
        # lead to a more effective activator (more negative ΔΔG_NAD)?
        # A positive correlation value here means: as Energy goes up (less favorable), ΔΔG_NAD goes up (less activating).
        # A NEGATIVE correlation is expected: more stabilization (lower Energy) -> more activation (lower ΔΔG_NAD).
        
        try:
            correlation = subset['Energy'].corr(subset['ΔΔG_NAD'])
        except Exception:
            correlation = np.nan # Not enough data points

        analysis_results.append({
            'Allosteric Residue': residue,
            'Average Energy (kcal/mol)': subset['Energy'].mean(),
            'Frequency (Best Poses)': subset['Residue'].count(),
            'Corr. (Residue E vs ΔΔG_NAD)': correlation
        })

    final_report_df = pd.DataFrame(analysis_results)
    
    # Sort by the correlation coefficient (most negative first) to find the residues
    # whose favorable binding directly tracks with increased activation.
    final_report_df.sort_values(by='Corr. (Residue E vs ΔΔG_NAD)', ascending=True, inplace=True)
    
    print("\n--- Allosteric Residues Contributing MOST to NAD Stabilization (Best Poses) ---")
    print("\n*Sorted by Correlation (Negative = More Stabilization -> More Activation)*")
    print(final_report_df.to_markdown(index=False, floatfmt=".3f"))
    
    # Save the final report
    final_report_df.to_csv("Allosteric_Activation_Contribution.csv", index=False, float_format='%.3f')
    print("\n✅ Final report saved to **Allosteric_Activation_Contribution.csv**.")

if __name__ == "__main__":
    analyze_best_pose_hotspots()
